This example may be too complex for readers to follow. Consider shortening it if possible.
The following code snippet shows a demonstration on how to add a <a data-href="Vercengen" href="CTD (Confoederatio, Technical Division)/Documentation/Technical (Frontend)/Vercengen/Vercengen.html" class="internal-link" target="_self" rel="noopener nofollow">Vercengen</a> scene tree with proper type creation and DALS integration. This example is taken from <a data-href="CRD (Confoederatio, Research Division)/Documentation/Software/Naissance/Naissance" href="CRD (Confoederatio, Research Division)/Documentation/Software/Naissance/Naissance.html" class="internal-link" target="_self" rel="noopener nofollow">CRD (Confoederatio, Research Division)/Documentation/Software/Naissance/Naissance</a> 1.6b Falkland.global.UI_LeftbarHierarchy = class { static instances = []; constructor () { this.groups = {}; this.hierarchy_obj = {}; this.items = {}; this.value = new ve.HTML("Loading ..", { style: { padding: 0 } }); this.refresh(); UI_LeftbarHierarchy.instances.push(this); } drawFeatures () { //Iterate over all naissance.FeatureGroups/naissance.FeatureLayers and render them recursively for (let i = 0; i &lt; naissance.Feature.instances.length; i++) { let local_feature = naissance.Feature.instances[i]; if (!local_feature._parent) this.hierarchy_obj[`${local_feature.class_name}-${local_feature.id}`] = local_feature.drawHierarchyDatatype(); } } drawGeometries () { //Iterate over all naissance.Geometries and render them at base for (let i = 0; i &lt; naissance.Geometry.instances.length; i++) { let local_geometry = naissance.Geometry.instances[i]; if (!local_geometry.parent &amp;&amp; local_geometry.drawHierarchyDatatype) this.hierarchy_obj[`${local_geometry.class_name}-${local_geometry.id}`] = local_geometry.drawHierarchyDatatype(); } } refresh () { //Declare local instance variables let actions_bar = new ve.HierarchyDatatype({ create_new_group: new ve.Button(() =&gt; { let feature_id = Class.generateRandomID(naissance.Feature); DALS.Timeline.parseAction({ options: { name: "Create Group", key: "create_group" }, value: [{ type: "FeatureGroup", create_group: { id: feature_id } }] }); }, { name: "&lt;icon&gt;create_new_folder&lt;/icon&gt;", tooltip: "Create New Group" }), create_new_layer: new ve.Button(() =&gt; { let feature_id = Class.generateRandomID(naissance.Feature); DALS.Timeline.parseAction({ options: { name: "Create Layer", key: "create_layer" }, value: [{ type: "FeatureLayer", create_layer: { id: feature_id } }] }); }, { name: "&lt;icon&gt;layers&lt;/icon&gt;", tooltip: "Create New Layer" }), create_new_sketch_map: new ve.Button(() =&gt; { let feature_id = Class.generateRandomID(naissance.Feature); DALS.Timeline.parseAction({ options: { name: "Create Sketch Map", key: "create_sketch_map" }, value: [{ type: "FeatureSketchMap", create_sketch_map: { id: feature_id } }] }); }, { name: "&lt;icon&gt;app_registration&lt;/icon&gt;", tooltip: "Create New Sketch Map" }), create_new_tile_layer: new ve.Button(() =&gt; { let feature_id = Class.generateRandomID(naissance.Feature); DALS.Timeline.parseAction({ options: { name: "Create Tile Layer", key: "create_tile_layer" }, value: [{ type: "FeatureTileLayer", create_tile_layer: { id: feature_id } }] }); }, { name: "&lt;icon&gt;view_module&lt;/icon&gt;", tooltip: "Create New Tile Layer" }) }, { disabled: true, style: { ".nst-content": { paddingRight: 0 } } }); actions_bar.element.classList.add("actions-bar"); let geometries_at_top = (global?.main?.settings?.hierarchy_ordering === "geometries_at_top"); this.hierarchy_obj = {}; if (!geometries_at_top) { this.drawFeatures(); this.drawGeometries(); } else { this.drawGeometries(); this.drawFeatures(); } let current_hierarchy = new ve.Hierarchy({ actions_bar: actions_bar, ...this.hierarchy_obj }, { onuserchange: (v, e) =&gt; { let allow_reassignment = [true, undefined]; let instance = e.on_stop_data.movedNode?.instance?.options?.instance; let old_parent = e.on_stop_data.originalParentItem?.instance?.options?.instance; let new_parent = e.on_stop_data.newParentItem?.instance?.options?.instance; if (new_parent === undefined &amp;&amp; instance) { if (instance.parent &amp;&amp; instance.parent.entities) for (let i = instance.parent.entities.length - 1; i &gt;= 0; i--) if (instance.parent.entities[i].class_name === instance.class_name &amp;&amp; instance.parent.entities[i].id === instance.id) { instance.parent.entities.splice(i, 1); break; } //Remove instance._parent instance.parent = undefined; this.refresh(); } //1. Check if allow_reassignment[0] is true { //1.1. Fetch all_child_els class names that may forbid nesting let all_child_els = e.on_stop_data.movedNode.querySelectorAll("li[component='ve-hierarchy-datatype']"); let cannot_nest_class_names = []; //Make sure that instances cannot be directly nested if disallowed if (!instance) console.warn(`UI_LeftbarHierarchy: .options.instance is not defined. Are you sure that the class name associated with`, e.on_stop_data.movedNode, `has a defined .options.instance in its drawHierarchyDatatype()?`); //Populate cannot_nested_class_names if (instance.cannot_nest_self) if (!cannot_nest_class_names.includes(instance.class_name)) cannot_nest_class_names.push(instance.class_name); for (let i = 0; i &lt; all_child_els.length; i++) { let local_instance = all_child_els[i].instance.options.instance; if (local_instance &amp;&amp; !cannot_nest_class_names.includes(local_instance.class_name)) if (local_instance.cannot_nest_self) cannot_nest_class_names.push(local_instance.class_name); } //1.2. Check if reassignment is allowed, or if it violates self-nesting rules let all_parent_els = HTML.getAllParentElements(e.on_stop_data.movedNode); //Iterate over all_parent_els in reverse to check if the same class_name is up the tree for (let i = all_parent_els.length - 1; i &gt;= 0; i--) if (all_parent_els[i].getAttribute("component") === "ve-hierarchy-datatype") { let local_instance = all_parent_els[i].instance.options.instance; if (cannot_nest_class_names.includes(local_instance.class_name)) allow_reassignment = [false, local_instance.class_name]; } } //2. Check if user is attempting to drag it before the control element let all_sibling_li_els = e.on_stop_data.movedNode.parentElement.children; for (let i = 0; i &lt; all_sibling_li_els.length; i++) if (all_sibling_li_els[i].classList.contains("actions-bar")) if (i &gt; 0) { veToast(`You cannot drag an item before the actions bar.`); this.refresh(); return; } //3. If reassignment is allowed, reassign the present entity to its new group if (allow_reassignment[0]) { //3.1. Remove from the .entities of any old naissance.Feature that contains it for (let i = 0; i &lt; naissance.Feature.instances.length; i++) { let local_feature = naissance.Feature.instances[i]; if (local_feature.entities) for (let x = local_feature.entities.length - 1; x &gt;= 0; x--) if (local_feature.entities[x].class_name === instance.class_name &amp;&amp; local_feature.entities[x].id === instance.id) local_feature.entities.splice(x, 1); } //3.2. Reconstruct new_parent.entities if (new_parent &amp;&amp; new_parent.entities) { let new_parent_entity_els = e.on_stop_data.newParentItem.querySelectorAll("ol &gt; li[component='ve-hierarchy-datatype']"); new_parent.entities = []; for (let i = 0; i &lt; new_parent_entity_els.length; i++) try { new_parent.entities.push(new_parent_entity_els[i].instance.options.instance); } catch (e) { console.warn(e); } instance.parent = new_parent; } } else { veToast(`${allow_reassignment[1]} cannot nest itself.`); setTimeout(() =&gt; this.refresh(), 100); } //3.3. Call renderer update main.renderer.update(); }, style: { padding: 0, "li.nst-item &gt; .nst-content": { width: "20rem" } } }); //3. Attach event handlers, select classes to all elements in this.hierarchy_obj let all_hierarchy_els = current_hierarchy.element.querySelectorAll("li[component='ve-hierarchy-datatype']"); for (let i = 0; i &lt; all_hierarchy_els.length; i++) { let local_instance = all_hierarchy_els[i]?.instance?.options?.instance; let local_value = all_hierarchy_els[i]?.instance; //console.log(local_instance, local_value); if (local_instance) { (main.brush?.selected_feature?.id === local_instance.id) ? local_value.element.classList.add("naissance-selected-feature") : local_value.element.classList.remove("naissance-selected-feature"); let component_handler_el = local_value.element.querySelector(".nst-content"); component_handler_el.onclick = (e) =&gt; { if ( document.querySelector(`button:hover, input:focus, [component="ve-button"]:hover`) ) return; //console.log(e.target, local_instance.element) if (local_instance instanceof naissance.Feature &amp;&amp; local_instance.entities !== undefined) { DALS.Timeline.parseAction({ options: { name: "Select Feature", key: "select_feature" }, value: [{ type: "Brush", select_feature_id: local_instance.id }] }); } else { //Selection logic for naissance.Geometry let already_selected = (main.brush.selected_geometry?.id === local_instance.id); if (!already_selected) { if (!HTML.ctrl_pressed) { DALS.Timeline.parseAction({ options: { name: "Select Geometry", key: "select_geometry" }, value: [{ type: "Brush", select_geometry_id: local_instance.id }] }); } else { local_instance.selected = (!local_instance.selected); } } //Deselect if already selected else { DALS.Timeline.parseAction({ options: { name: "Deselect Geometry", key: "deselect_geometry" }, value: [{ type: "Brush", select_geometry_id: false }] }); } } }; } } this.value.element.innerHTML = ""; this.value.element.appendChild(current_hierarchy.element); } static refresh () { for (let i = 0; i &lt; UI_LeftbarHierarchy.instances.length; i++) UI_LeftbarHierarchy.instances[i].refresh(); } };

