Deck.gl (React):// ==UserScript==
// @name Expose Deck.gl Layers
// @namespace http://tampermonkey.net/
// @version 1.2
// @description Intercepts Deck.gl Layers to expose data
// @author Vis Tacitus
// @match *://*/*
// @run-at document-start
// @grant none
// ==/UserScript== (function () { window.findDeckData = function () { // 1. Find the canvas element used by Deck.gl const canvas = document.querySelector(".mapboxgl-canvas") || document.querySelector("canvas"); if (!canvas) return console.error("Could not find map canvas."); // 2. Find the React Internal Key const fiberKey = Object.keys(canvas).find((key) =&gt; key.startsWith("__reactFiber") || key.startsWith("__reactInternalInstance")); if (!fiberKey) return console.error("Could not find React Fiber on this element."); // 3. Walk up the React tree to find the DeckGL component let walker = canvas[fiberKey]; let layers = null; while (walker) { if (walker.memoizedProps &amp;&amp; walker.memoizedProps.layers) { layers = walker.memoizedProps.layers; break; } walker = walker.return; } if (layers) { window.deckgl_layers = layers; console.log("%c Found Deck.gl Layers! ", "background: #222; color: #00e676; font-size: 14px;"); // Create a summary for the user const summary = layers.map(l =&gt; ({ id: l.id, type: l.constructor.name, dataLength: l.props.data ? (Array.isArray(l.props.data) ? l.props.data.length : 'Complex/Tile') : 0 })); console.table(summary); console.log("Access them via: window.deckgl_layers"); } else { console.warn("Found React tree but no 'layers' prop. Try zooming/panning the map and running this again."); } }
})();
Leaflet:// ==UserScript==
// @name Leaflet Map Instance Tracker
// @namespace http://tampermonkey.net/
// @version 1.0
// @description Intercepts and stores all Leaflet map instances in a global array.
// @match *://*/*
// @run-at document-start
// @grant none
// ==/UserScript== (function () { "use strict"; // This array will hold all map instances found on the page window.capturedMaps = []; let leafletBackend; // We define a getter/setter on window.L to catch the moment Leaflet loads Object.defineProperty(window, "L", { get: function () { return leafletBackend; }, set: function (newLeaflet) { leafletBackend = newLeaflet; // Ensure we have the Map object and haven't hooked it yet if (leafletBackend &amp;&amp; leafletBackend.Map &amp;&amp; !leafletBackend._hooked) { leafletBackend._hooked = true; console.log("Leaflet detected! Injecting initialization hook..."); leafletBackend.Map.addInitHook(function () { window.capturedMaps.push(this); console.log("New Leaflet map instance captured:", this); }); } }, configurable: true, }); // Optional: Expose a helper function to the console to interact with maps window.getMaps = () =&gt; window.capturedMaps;
})();
MapLibre:// ==UserScript==
// @name MapLibre Geometry Extractor
// @namespace http://tampermonkey.net/
// @version 4.0
// @description Pull all coordinates from all sources on the map
// @author Vis Tacitus
// @match *://*/*
// @grant unsafeWindow
// @run-at document-start
// ==/UserScript== (function () { "use strict"; const win = typeof unsafeWindow !== "undefined" ? unsafeWindow : window; win.maplibre_maps = []; // Capture instance (Nuclear Option) Object.defineProperty(Object.prototype, "_container", { set: function (val) { if (this.getStyle &amp;&amp; this.queryRenderedFeatures) { if (!win.maplibre_maps.includes(this)) win.maplibre_maps.push(this); } this.__secret_container_ref = val; }, get: function () { return this.__secret_container_ref; }, configurable: true, });
})();
OpenLayers:// ==UserScript==
// @name Capture OpenLayers Map
// @namespace http://tampermonkey.net/
// @version 1.0
// @description Captures the OpenLayers map instance by intercepting the constructor.
// @author Vis Tacitus
// @match *://*/*
// @run-at document-start
// @grant none
// ==/UserScript== (function () { "use strict"; /** * This script intercepts the OpenLayers Map constructor. * It stores the map instance in window.capturedMap for easy access. */ let rawOl = undefined; Object.defineProperty(window, "ol", { get: function () { return rawOl; }, set: function (value) { rawOl = value; // Check if the value being set is the OpenLayers object containing the Map constructor if (rawOl &amp;&amp; rawOl.Map &amp;&amp; !rawOl.Map.isIntercepted) { const OriginalMap = rawOl.Map; // Wrap the original constructor const MapProxy = function (options) { const instance = new OriginalMap(options); window.capturedMap = instance; console.log("OpenLayers Map captured:", instance); console.log( "Access it via: window.capturedMap", ); return instance; }; // Ensure inheritance and identification work correctly MapProxy.prototype = OriginalMap.prototype; MapProxy.isIntercepted = true; rawOl.Map = MapProxy; } }, configurable: true, enumerable: true, });
})();

function getPolitiesLayerFromComponent () { let all_nodes = document.querySelectorAll("*");
for (const node of all_nodes) { if (node.__ngContext__) { const contextArray = Array.isArray(node.__ngContext__) ? node.__ngContext__ : [node.__ngContext__]; for (const item of contextArray) { if (item &amp;&amp; typeof item === "object" &amp;&amp; "politiesLayer" in item) { console.log("Found instance globally on standard node:", item); return item.polities_layer_geojson; } } } }
}
console.log(getPolitiesLayerFromComponent());

/** * Extractor for OpenLayers features stored in Pinia. * Navigates: map-store -&gt; layers -&gt; vessels_markers -&gt; values_ -&gt; source */
window.getVesselsFromOL = function () { // 1. Access Pinia State directly (Reliable) const root = document.querySelector("#app") || document.querySelector("[data-v-app]"); if (!root || !root.__vue_app__) return "Vue 3 app not found."; const pinia = root.__vue_app__.config.globalProperties.$pinia; const state = pinia.state.value; const mapStore = state["map-store"]; if (!mapStore || !mapStore.layers || !mapStore.layers.vessels_markers) { return "Could not navigate to map-store.layers.vessels_markers"; } // 2. Navigate to the Source (using your hint) const layer = mapStore.layers.vessels_markers; const source = layer.values_?.source || layer.source; if (!source) return "OpenLayers Source not found."; // 3. Get Features (This pulls the live array of ship objects) const features = source.getFeatures ? source.getFeatures() : []; if (features.length === 0) return "No features found in the source."; /** * Manual Projection Converter (EPSG:3857 to EPSG:4326) * Required because OpenLayers coordinates are in meters. */ const toLonLat = (coords) =&gt; { const x = coords[0]; const y = coords[1]; const lon = (x * 180) / 20037508.34; let lat = (y * 180) / 20037508.34; lat = (180 / Math.PI) * (2 * Math.atan(Math.exp((lat * Math.PI) / 180)) - Math.PI / 2); return [lon, lat]; }; // 4. Build GeoJSON const geojson = { type: "FeatureCollection", features: features.map((f) =&gt; { const geom = f.getGeometry(); const rawCoords = geom.getCoordinates(); const cleanCoords = toLonLat(rawCoords); // Get metadata (MMSI, Name, etc.) // OL stores these in the 'values_' property or via getProperties() const props = f.getProperties ? f.getProperties() : (f.values_ || {}); // Clean up properties to avoid circular references const cleanProps = { ...props }; delete cleanProps.geometry; return { type: "Feature", geometry: { type: "Point", coordinates: cleanCoords, }, properties: cleanProps, }; }), }; console.log(`Successfully extracted ${geojson.features.length} vessels.`); return geojson;
}; /** * Utility to download the resulting GeoJSON */
window.downloadVessels = function() { const data = window.getVesselsFromOL(); if (typeof data === 'string') { console.error(data); return; } const blob = new Blob([JSON.stringify(data, null, 2)], {type: "application/json"}); const url = URL.createObjectURL(blob); const a = document.createElement("a"); a.href = url; a.download = `vessels_data_${Date.now()}.geojson`; a.click(); URL.revokeObjectURL(url);
}; URL: <a rel="noopener nofollow" class="external-link is-unresolved" href="https://www.aisfriends.com/embed?lat=49&amp;lon=6.3&amp;zoom=2&amp;types=4&amp;names=true&amp;menu=false" target="_self">https://www.aisfriends.com/embed?lat=49&amp;lon=6.3&amp;zoom=2&amp;types=4&amp;names=true&amp;menu=false</a>https://www.aisfriends.com/vessels/bounding-box?lon_min=-180&amp;lat_min=-90&amp;lon_max=180&amp;lat_max=90&amp;zoom=12&amp;types=4

This is a list of default easing animations for <a data-href="Echarts" href="CTD (Confoederatio, Technical Division)/Documentation/Technical (Backend)/External Dependencies/Echarts/Echarts.html" class="internal-link" target="_self" rel="noopener nofollow">Echarts</a>. You can view the exact bindings for ease animations at <a data-href="Echarts Bindings" href="CTD (Confoederatio, Technical Division)/Documentation/Technical (Backend)/External Dependencies/Echarts/Echarts Bindings.html" class="internal-link" target="_self" rel="noopener nofollow">Echarts Bindings</a>. This demo is also available <a data-tooltip-position="top" aria-label="https://echarts.apache.org/examples/en/editor.html?c=line-easing" rel="noopener nofollow" class="external-link is-unresolved" href="https://echarts.apache.org/examples/en/editor.html?c=line-easing" target="_self">publicly</a>.const easingFuncs = { linear: function (k) { return k; }, quadraticIn: function (k) { return k * k; }, quadraticOut: function (k) { return k * (2 - k); }, quadraticInOut: function (k) { if ((k *= 2) &lt; 1) { return 0.5 * k * k; } return -0.5 * (--k * (k - 2) - 1); }, cubicIn: function (k) { return k * k * k; }, cubicOut: function (k) { return --k * k * k + 1; }, cubicInOut: function (k) { if ((k *= 2) &lt; 1) { return 0.5 * k * k * k; } return 0.5 * ((k -= 2) * k * k + 2); }, quarticIn: function (k) { return k * k * k * k; }, quarticOut: function (k) { return 1 - --k * k * k * k; }, quarticInOut: function (k) { if ((k *= 2) &lt; 1) { return 0.5 * k * k * k * k; } return -0.5 * ((k -= 2) * k * k * k - 2); }, quinticIn: function (k) { return k * k * k * k * k; }, quinticOut: function (k) { return --k * k * k * k * k + 1; }, quinticInOut: function (k) { if ((k *= 2) &lt; 1) { return 0.5 * k * k * k * k * k; } return 0.5 * ((k -= 2) * k * k * k * k + 2); }, sinusoidalIn: function (k) { return 1 - Math.cos((k * Math.PI) / 2); }, sinusoidalOut: function (k) { return Math.sin((k * Math.PI) / 2); }, sinusoidalInOut: func